2942→                // DELETE 트랜잭션 커밋 (INSERT는 개별 저장)
2943→                transaction.Commit();
2944→                transaction.Dispose();
2945→                transaction = null;
2946→                Logger.Log($"[자동설정] 기존 포인트 삭제 완료");
2947→
2948→                // Point_ID는 1부터 시작
2949→                int maxPointId = 0;
2950→
2951→                Logger.Log($"[자동설정] 신규 등록 시작: {pointCount}개 (개별 저장)");
2952→
2953→                // SPOT 모드 여부 확인
2954→                bool isSpotMode = GlobalValues.weldMode == "SPOT";
2955→
2956→                // Table_Seq에 새 포인트 추가
2957→                for (int i = 0; i < pointCount; i++)
2958→                {
2959→                    try
2960→                    {
2961→                        // 매 포인트마다 진행률 출력
2962→                        Logger.Log($"[자동설정] 등록 진행: {i + 1}/{pointCount}");
2963→
2964→                        int newPointId = maxPointId + i + 1;
2965→
2966→                        // 배열 범위 체크 (방어 코드)
2967→                        if (i >= ampData.Count || i >= voltData.Count || i >= flowData.Count)
2968→                        {
2969→                            Logger.Log($"[자동설정] Point {newPointId}: 인덱스 초과 - 건너뜀");
2970→                            continue;
2971→                        }
2972→
2973→                        // 데이터 유효성 검사
2974→                        if (ampData[i] == null || ampData[i].Count == 0 ||
2975→                            voltData[i] == null || voltData[i].Count == 0 ||
2976→                            flowData[i] == null || flowData[i].Count == 0)
2977→                        {
2978→                            Logger.Log($"[자동설정] Point {newPointId}: 데이터 없음 - 건너뜀");
2979→                            continue;
2980→                        }
2981→
2982→                        // SPOT 모드: 전부 Max 값 사용
2983→                        // CO2 모드: Amp/Volt는 Average, Flow만 Max
2984→                        double baseAmp, baseVolt, baseFlow;
2985→                        string ampVoltType;
2986→                        if (isSpotMode)
2987→                        {
2988→                            baseAmp = Math.Round(ampData[i].Max(), 2);
2989→                            baseVolt = Math.Round(voltData[i].Max(), 2);
2990→                            baseFlow = Math.Round(flowData[i].Max(), 2);
2991→                            ampVoltType = "Max";
2992→                        }
2993→                        else
2994→                        {
2995→                            baseAmp = Math.Round(ampData[i].Average(), 2);
2996→                            baseVolt = Math.Round(voltData[i].Average(), 2);
2997→                            baseFlow = Math.Round(flowData[i].Max(), 2);  // Flow만 Max
2998→                            ampVoltType = "Average";
2999→                        }
3000→
3001→                        // NaN/Infinity 체크
3002→                        if (double.IsNaN(baseAmp) || double.IsInfinity(baseAmp) ||
3003→                            double.IsNaN(baseVolt) || double.IsInfinity(baseVolt) ||
3004→                            double.IsNaN(baseFlow) || double.IsInfinity(baseFlow))
3005→                        {
3006→                            Logger.Log($"[자동설정] Point {newPointId}: 잘못된 값 (Amp:{baseAmp}, Volt:{baseVolt}, Flow:{baseFlow}) - 건너뜀");
3007→                            continue;
3008→                        }
3009→
3010→                        // ±30% 스펙 계산
3011→                        double ampMin = Math.Round(baseAmp * 0.7, 2);
3012→                        double ampMax = Math.Round(baseAmp * 1.3, 2);
3013→                        double voltMin = Math.Round(baseVolt * 0.7, 2);
3014→                        double voltMax = Math.Round(baseVolt * 1.3, 2);
3015→                        double flowMin = Math.Round(baseFlow * 0.7, 2);
3016→                        double flowMax = Math.Round(baseFlow * 1.3, 2);
3017→
3018→                        using (var cmd = new OleDbCommand(@"
3019→                            INSERT INTO Table_Seq
3020→                            (Jig_ID, Point_ID, Value1_Max, Value1_Min, Value2_Max, Value2_Min, Value3_Max, Value3_Min,
3021→                             Value1_Tol, Value2_Tol, Value3_Tol, Value1_Type, Value2_Type, Value3_Type,
3022→                             StartSector, EndSector, Pass, Image_Coord_X, Image_Coord_Y, Image_Size_X, Image_Size_Y, graphWidth)
3023→                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", conn))
3024→                        {
3025→                            cmd.Parameters.AddWithValue("?", jigId);
3026→                            cmd.Parameters.AddWithValue("?", newPointId.ToString());
3027→                            cmd.Parameters.AddWithValue("?", ampMax);
3028→                            cmd.Parameters.AddWithValue("?", ampMin);
3029→                            cmd.Parameters.AddWithValue("?", voltMax);
3030→                            cmd.Parameters.AddWithValue("?", voltMin);
3031→                            cmd.Parameters.AddWithValue("?", flowMax);
3032→                            cmd.Parameters.AddWithValue("?", flowMin);
3033→                            cmd.Parameters.AddWithValue("?", 1);  // Value1_Tol (Offset=1)
3034→                            cmd.Parameters.AddWithValue("?", 1);  // Value2_Tol (Offset=1)
3035→                            cmd.Parameters.AddWithValue("?", 1);  // Value3_Tol (Offset=1)
3036→                            cmd.Parameters.AddWithValue("?", ampVoltType);  // Value1_Type (Amp)
3037→                            cmd.Parameters.AddWithValue("?", ampVoltType);  // Value2_Type (Volt)
3038→                            cmd.Parameters.AddWithValue("?", "Max");         // Value3_Type (Flow) - 항상 Max
3039→                            cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // StartSector (SPOT: 0%, CO2: 5% trim)
3040→                            cmd.Parameters.AddWithValue("?", isSpotMode ? 0 : 5);  // EndSector (SPOT: 0%, CO2: 5% trim)
3041→                            cmd.Parameters.AddWithValue("?", 0);   // Pass (false)
3042→                            cmd.Parameters.AddWithValue("?", 0);   // Image_Coord_X
3043→                            cmd.Parameters.AddWithValue("?", 0);   // Image_Coord_Y
3044→                            cmd.Parameters.AddWithValue("?", 50);  // Image_Size_X
3045→                            cmd.Parameters.AddWithValue("?", 50);  // Image_Size_Y
3046→                            cmd.Parameters.AddWithValue("?", 10);  // graphWidth
3047→                            cmd.ExecuteNonQuery();
3048→                        }
3049→
3050→                        // UI 응답성 확보를 위한 짧은 대기
3051→                        Thread.Sleep(10);
3052→                    }
3053→                    catch (Exception ex)
3054→                    {
3055→                        Logger.Log($"[자동설정] Point {i + 1} 등록 오류: {ex.Message}");
3056→                        Logger.Log($"[자동설정] StackTrace: {ex.StackTrace}");
3057→                        // 이 포인트는 건너뛰고 계속 진행
3058→                    }
3059→                }
3060→
3061→                Logger.Log($"[자동설정] INSERT 완료: {pointCount}개");
3062→
3063→                return true;
3064→            }
3065→            catch (Exception ex)
3066→            {
3067→                Logger.Log($"[자동설정] DB 오류: {ex.Message}");
3068→                Logger.Log($"[자동설정] StackTrace: {ex.StackTrace}");
3069→
3070→                try
3071→                {
3072→                    if (transaction != null)
3073→                    {
3074→                        transaction.Rollback();
3075→                        Logger.Log($"[자동설정] 트랜잭션 롤백 완료");
3076→                    }
3077→                }
3078→                catch (Exception rollbackEx)
3079→                {
3080→                    Logger.Log($"[자동설정] 롤백 오류: {rollbackEx.Message}");
3081→                }
3082→
3083→                return false;
3084→            }
3085→            finally
3086→            {
3087→                if (transaction != null)
3088→                {
3089→                    transaction.Dispose();
3090→                }
