3105→            using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig WHERE Jig_ID LIKE 'AUTO_%'", conn))
3106→            {
3107→                using (var reader = cmd.ExecuteReader())
3108→                {
3109→                    while (reader.Read())
3110→                    {
