3284→        /// <summary>
3285→        /// 숫자를 ioOption 형식으로 변환 (5비트 바이너리)
3286→        /// 예: 1→"1", 3→"1/2", 16→"5", 31→"1/2/3/4/5"
3287→        /// </summary>
3288→        private string GetIoOptionFromNumber(int num)
3289→        {
3290→            List<int> bits = new List<int>();
3291→            for (int i = 0; i < 5; i++)
3292→            {
3293→                if ((num & (1 << i)) != 0)
3294→                    bits.Add(i + 1);  // 1-based (IO.IN[1]~IO.IN[5])
3295→            }
3296→            return string.Join("/", bits);
3297→        }
